import requests
import json
from pydantic import BaseModel, Field


class Tools:
    class Valves(BaseModel):
        NEWS_API_KEY: str = Field(
            default="", description="Free API key from newsapi.org"
        )

    def __init__(self):
        self.valves = self.Valves()

    def _check_key(self):
        if not self.valves.NEWS_API_KEY:
            return "NEWS_API_KEY not set. Get a free key at newsapi.org"
        return None

    def get_top_headlines(self, category: str = "business", country: str = "us") -> str:
        """
        Get top news headlines by category and country.
        category: business, technology, science, health, sports, entertainment, general
        country: us, gb, ca, au, de, fr, jp, in, cn, br
        """
        err = self._check_key()
        if err:
            return err
        try:
            params = {
                "apiKey": self.valves.NEWS_API_KEY,
                "category": category,
                "country": country,
                "pageSize": 10,
            }
            res = requests.get(
                "https://newsapi.org/v2/top-headlines", params=params
            ).json()
            return json.dumps(
                [
                    {
                        "title": a["title"],
                        "source": a["source"]["name"],
                        "author": a.get("author"),
                        "description": a.get("description"),
                        "published": a["publishedAt"],
                        "url": a["url"],
                    }
                    for a in res.get("articles", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def search_news(
        self, query: str, sort_by: str = "publishedAt", days_back: int = 7
    ) -> str:
        """
        Search all news articles for any query.
        query: e.g. 'Apple earnings', 'Bitcoin crash', 'Federal Reserve rates'
        sort_by: publishedAt, relevancy, popularity
        days_back: how many days back to search (1-30)
        """
        err = self._check_key()
        if err:
            return err
        try:
            from datetime import datetime, timedelta

            from_date = (datetime.now() - timedelta(days=days_back)).strftime(
                "%Y-%m-%d"
            )
            params = {
                "apiKey": self.valves.NEWS_API_KEY,
                "q": query,
                "sortBy": sort_by,
                "from": from_date,
                "language": "en",
                "pageSize": 10,
            }
            res = requests.get(
                "https://newsapi.org/v2/everything", params=params
            ).json()
            return json.dumps(
                [
                    {
                        "title": a["title"],
                        "source": a["source"]["name"],
                        "author": a.get("author"),
                        "description": a.get("description"),
                        "content": a.get("content"),
                        "published": a["publishedAt"],
                        "url": a["url"],
                    }
                    for a in res.get("articles", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_financial_news(self, query: str) -> str:
        """
        Get latest financial and market news for a specific topic.
        query examples: 'AAPL stock', 'Bitcoin', 'Fed interest rates', 'oil prices', 'inflation'
        """
        err = self._check_key()
        if err:
            return err
        try:
            params = {
                "apiKey": self.valves.NEWS_API_KEY,
                "q": query,
                "sortBy": "publishedAt",
                "language": "en",
                "pageSize": 10,
                "domains": "reuters.com,bloomberg.com,cnbc.com,ft.com,wsj.com,forbes.com,marketwatch.com,businessinsider.com",
            }
            res = requests.get(
                "https://newsapi.org/v2/everything", params=params
            ).json()
            return json.dumps(
                [
                    {
                        "title": a["title"],
                        "source": a["source"]["name"],
                        "description": a.get("description"),
                        "published": a["publishedAt"],
                        "url": a["url"],
                    }
                    for a in res.get("articles", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_crypto_news(self) -> str:
        """Get latest cryptocurrency news from top financial sources."""
        err = self._check_key()
        if err:
            return err
        try:
            params = {
                "apiKey": self.valves.NEWS_API_KEY,
                "q": "cryptocurrency OR bitcoin OR ethereum OR crypto",
                "sortBy": "publishedAt",
                "language": "en",
                "pageSize": 10,
            }
            res = requests.get(
                "https://newsapi.org/v2/everything", params=params
            ).json()
            return json.dumps(
                [
                    {
                        "title": a["title"],
                        "source": a["source"]["name"],
                        "description": a.get("description"),
                        "published": a["publishedAt"],
                        "url": a["url"],
                    }
                    for a in res.get("articles", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_market_news(self) -> str:
        """Get latest stock market and financial markets news."""
        err = self._check_key()
        if err:
            return err
        try:
            params = {
                "apiKey": self.valves.NEWS_API_KEY,
                "q": "stock market OR S&P 500 OR Wall Street OR Federal Reserve",
                "sortBy": "publishedAt",
                "language": "en",
                "pageSize": 10,
            }
            res = requests.get(
                "https://newsapi.org/v2/everything", params=params
            ).json()
            return json.dumps(
                [
                    {
                        "title": a["title"],
                        "source": a["source"]["name"],
                        "description": a.get("description"),
                        "published": a["publishedAt"],
                        "url": a["url"],
                    }
                    for a in res.get("articles", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_news_sources(self, category: str = "business") -> str:
        """
        Get all available news sources.
        category: business, technology, science, health, sports, entertainment, general
        """
        err = self._check_key()
        if err:
            return err
        try:
            params = {
                "apiKey": self.valves.NEWS_API_KEY,
                "category": category,
                "language": "en",
            }
            res = requests.get(
                "https://newsapi.org/v2/top-headlines/sources", params=params
            ).json()
            return json.dumps(
                [
                    {
                        "id": s["id"],
                        "name": s["name"],
                        "description": s["description"],
                        "url": s["url"],
                        "country": s["country"],
                    }
                    for s in res.get("sources", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_news_by_source(self, source_id: str) -> str:
        """
        Get news from a specific source.
        source_id examples: reuters, bloomberg, cnbc, the-wall-street-journal,
        financial-times, fortune, business-insider, techcrunch
        """
        err = self._check_key()
        if err:
            return err
        try:
            params = {
                "apiKey": self.valves.NEWS_API_KEY,
                "sources": source_id,
                "pageSize": 10,
            }
            res = requests.get(
                "https://newsapi.org/v2/top-headlines", params=params
            ).json()
            return json.dumps(
                [
                    {
                        "title": a["title"],
                        "description": a.get("description"),
                        "published": a["publishedAt"],
                        "url": a["url"],
                    }
                    for a in res.get("articles", [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"
